import React from 'react';
import { Box, Container, Grid, Stack } from '@mui/material';
import SectionTitle from './SectionTitle';
import ServiceCard from './ServiceCard';
import {
  Web as WebIcon,
  PhoneAndroid as MobileIcon,
  SmartToy as BotIcon,
  Security as SecurityIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';

const ServiceSection = () => {
  const services = [
    {
      icon: <WebIcon fontSize="large" />,
      title: "Web Application Development",
      description: "End-to-end web application solutions with robust backend systems and intuitive user interfaces.",
      features: [
        "Secure authentication systems",
        "RESTful API development",
        "Database design & optimization",
        "Responsive UI/UX implementation"
      ],
      color: "#2196f3" // Blue
    },
    {
      icon: <MobileIcon fontSize="large" />,
      title: "Mobile Application Development",
      description: "Performant mobile applications with seamless backend integration and cross-platform compatibility.",
      features: [
        "Native & cross-platform solutions",
        "API integration",
        "Real-time data synchronization",
        "Offline-first functionality"
      ],
      color: "#00bcd4" // Teal
    },
    {
      icon: <BotIcon fontSize="large" />,
      title: "AI ChatBot Development",
      description: "Intelligent conversational agents powered by modern AI technologies and natural language processing.",
      features: [
        "Intent recognition systems",
        "Natural language processing",
        "Integration with third-party services",
        "Continuous training & improvement"
      ],
      color: "#7c4dff" // Purple
    },
    {
      icon: <SecurityIcon fontSize="large" />,
      title: "Security Consulting",
      description: "Comprehensive security audits and implementation of robust security measures for your applications.",
      features: [
        "Vulnerability assessment",
        "Security code reviews",
        "Authentication best practices",
        "Data encryption strategies"
      ],
      color: "#f44336" // Red
    }
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2
      }
    }
  };

  // Process services into pairs for 2-column layout
  const serviceRows = [];
  for (let i = 0; i < services.length; i += 2) {
    const row = services.slice(i, i + 2);
    serviceRows.push(row);
  }

  return (
    <Box sx={{ py: { xs: 8, md: 12 }, bgcolor: 'background.default' }}>
      <Container maxWidth="lg">
        <SectionTitle
          title="Services"
          subtitle="What I Can Do For You"
        />
        
        <Stack spacing={4} component={motion.div}
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}>
          {serviceRows.map((row, rowIndex) => (
            <Grid container spacing={4} key={rowIndex}>
              {row.map((service, index) => (
                <Grid item xs={12} md={6} key={index}>
                  <ServiceCard {...service} />
                </Grid>
              ))}
            </Grid>
          ))}
        </Stack>
      </Container>
    </Box>
  );
};

export default ServiceSection;
